  1→/**
  2→ * Backend Process Manager
  3→ *
  4→ * Spawns the Node.js backend as a child process using Electron's built-in
  5→ * Node runtime (ELECTRON_RUN_AS_NODE=1) in both dev and production.
  6→ * This ensures native modules (better-sqlite3, node-pty) compiled by
  7→ * electron-builder always match the runtime ABI — no system Node required.
  8→ *
  9→ * Parses the dynamic port from stdout, generates an auth token, and handles
 10→ * exit/restart with exponential backoff.
 11→ */
 12→
 13→import { spawn, type ChildProcess } from "child_process";
 14→import { join } from "path";
 15→import { existsSync, writeFileSync } from "fs";
 16→import { app, BrowserWindow } from "electron";
 17→import crypto from "crypto";
 18→
 19→let backendProcess: ChildProcess | null = null;
 20→let isQuitting = false;
 21→let restartAttempt = 0;
 22→let restartTimer: ReturnType<typeof setTimeout> | null = null;
 23→const MAX_RESTART_ATTEMPTS = 5;
 24→const STARTUP_TIMEOUT_MS = 30_000;
 25→
 26→export async function spawnBackend(): Promise<{ port: number; authToken: string }> {
 27→  const authToken = crypto.randomBytes(24).toString("hex");
 28→  const projectRoot = join(__dirname, "../..");
 29→  // Always use Electron's Node binary for the backend process.
 30→  // electron-builder install-app-deps compiles native modules (better-sqlite3, node-pty)
 31→  // against Electron's Node ABI. Using system node would cause MODULE_VERSION mismatch.
 32→  const backendRuntime = process.execPath;
 33→
 34→  // Resolve backend entry point
 35→  // Production: bundled CJS file (no tsx dependency needed)
 36→  // Development: server.cjs bootstraps tsx for live TypeScript
 37→  const backendEntry = app.isPackaged
 38→    ? join(process.resourcesPath, "backend", "server.bundled.cjs")
 39→    : join(projectRoot, "apps/backend/server.cjs");
 40→
 41→  // Database path — prefer legacy location (com.deus.ide) if it exists,
 42→  // otherwise use Electron's userData dir (~/Library/Application Support/deus/).
 43→  const legacyDbPath = join(app.getPath("appData"), "com.deus.ide", "deus.db");
 44→  const electronDbPath = join(app.getPath("userData"), "deus.db");
 45→  const dbPath = existsSync(legacyDbPath) ? legacyDbPath : electronDbPath;
 46→
 47→  // Sidecar bundle path
 48→  const sidecarPath = app.isPackaged
 49→    ? join(process.resourcesPath, "bin", "index.bundled.cjs")
 50→    : join(projectRoot, "apps/sidecar/dist/index.bundled.cjs");
 51→
 52→  // Notebook server bundle path
 53→  const notebookPath = app.isPackaged
 54→    ? join(process.resourcesPath, "bin", "notebook-server.bundled.cjs")
 55→    : join(projectRoot, "packages/mcp-notebook/dist/notebook-server.bundled.cjs");
 56→
 57→  return new Promise((resolve, reject) => {
 58→    backendProcess = spawn(backendRuntime, [backendEntry], {
 59→      cwd: app.isPackaged ? process.resourcesPath : join(projectRoot, "apps/backend"),
 60→      env: {
 61→        ...process.env,
 62→        ELECTRON_RUN_AS_NODE: "1",
 63→        DATABASE_PATH: dbPath,
 64→        SIDECAR_BUNDLE_PATH: sidecarPath,
 65→        NOTEBOOK_SERVER_BUNDLE_PATH: notebookPath,
 66→        AUTH_TOKEN: authToken,
 67→        PORT: "0", // Dynamic port allocation
 68→      },
 69→      stdio: ["ignore", "pipe", "pipe"],
 70→    });
 71→
 72→    let resolved = false;
 73→    let stdoutBuffer = "";
 74→
 75→    // Parse port from stdout
 76→    backendProcess.stdout?.on("data", (data: Buffer) => {
 77→      stdoutBuffer += data.toString();
 78→      const lines = stdoutBuffer.split("\n");
 79→      stdoutBuffer = lines.pop() ?? ""; // Keep incomplete last line in buffer
 80→      for (const line of lines) {
 81→        const trimmed = line.trim();
 82→        if (!trimmed) continue;
 83→
 84→        // Log backend stdout in dev mode
 85→        if (!app.isPackaged) {
 86→          console.log("[backend]", trimmed);
 87→        }
 88→
 89→        // Match both formats: "[BACKEND_PORT]12345" (primary) and
 90→        // "Backend server started on port 12345" (legacy fallback).
 91→        const portMatch =
 92→          trimmed.match(/^\[BACKEND_PORT\](\d+)$/) ||
 93→          trimmed.match(/Backend server started on port (\d+)/);
 94→        if (portMatch && !resolved) {
 95→          resolved = true;
 96→          restartAttempt = 0;
 97→          const port = parseInt(portMatch[1], 10);
 98→
 99→          // Write port to temp file so Chrome tabs (without electronAPI) can discover it.
100→          // The Vite dev server serves this via middleware in electron.vite.config.ts.
101→          if (!app.isPackaged) {
102→            try {
103→              const portFile = join(app.getPath("temp"), "deus-backend-port");
104→              writeFileSync(portFile, String(port));
105→            } catch {
106→              // Non-critical — only used for Chrome tab port discovery
107→            }
108→          }
109→
110→          resolve({ port, authToken });
111→        }
112→
113→        // Relay workspace init progress events to the renderer.
114→        // Backend emits: DEUS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
115→        // We parse the JSON and forward it as an IPC event to the renderer.
116→        // SYNC: Event name must match shared/events.ts (AppEventMap["workspace:progress"])
117→        if (trimmed.startsWith("DEUS_WORKSPACE_PROGRESS:")) {
118→          const jsonStr = trimmed.slice("DEUS_WORKSPACE_PROGRESS:".length);
119→          try {
120→            const payload = JSON.parse(jsonStr);
121→            const win = BrowserWindow.getAllWindows()[0];
122→            if (win) {
123→              win.webContents.send("workspace:progress", payload);
124→            }
125→          } catch {
126→            // Ignore malformed progress lines
127→          }
128→        }
129→      }
130→    });
131→
132→    backendProcess.stderr?.on("data", (data: Buffer) => {
133→      console.error("[backend:stderr]", data.toString().trim());
134→    });
135→
136→    backendProcess.on("exit", (code, signal) => {
137→      console.log(`[backend] Exited with code=${code} signal=${signal}`);
138→      backendProcess = null;
139→
140→      if (!resolved) {
141→        reject(new Error(`Backend exited before starting (code=${code})`));
142→        return;
143→      }
144→
145→      // Restart with exponential backoff (unless app is quitting)
146→      if (!isQuitting && restartAttempt < MAX_RESTART_ATTEMPTS) {
147→        restartAttempt++;
148→        const delay = Math.min(1000 * Math.pow(2, restartAttempt - 1), 30_000);
149→        console.log(`[backend] Restart attempt ${restartAttempt} in ${delay}ms`);
150→        restartTimer = setTimeout(() => {
151→          restartTimer = null;
152→          spawnBackend()
153→            .then(({ port, authToken: newAuthToken }) => {
154→              // Update env vars so IPC handlers (native:getBackendPort) return the new port
155→              process.env.DEUS_BACKEND_PORT = String(port);
156→              process.env.DEUS_AUTH_TOKEN = newAuthToken;
157→
158→              // Notify all renderer windows so they can invalidate their cached port
159→              // and reconnect WebSocket to the new address.
160→              for (const win of BrowserWindow.getAllWindows()) {
161→                win.webContents.send("backend:port-changed", { port });
162→              }
163→              console.log(`[backend] Restarted on port ${port}, notified renderer`);
164→            })
165→            .catch((err) => {
166→              console.error("[backend] Restart failed:", err);
167→            });
168→        }, delay);
169→      }
170→    });
171→
172→    backendProcess.on("error", (err) => {
173→      console.error("[backend] Spawn error:", err);
174→      if (!resolved) {
175→        reject(err);
176→      }
177→    });
178→
179→    // Timeout if backend doesn't start
180→    setTimeout(() => {
181→      if (!resolved) {
182→        resolved = true;
183→        backendProcess?.kill("SIGTERM");
184→        reject(new Error(`Backend startup timeout (${STARTUP_TIMEOUT_MS}ms)`));
185→      }
186→    }, STARTUP_TIMEOUT_MS);
187→  });
188→}
189→
190→export function stopBackend(): void {
191→  isQuitting = true;
192→  if (restartTimer) {
193→    clearTimeout(restartTimer);
194→    restartTimer = null;
195→  }
196→  if (backendProcess) {
197→    backendProcess.kill("SIGTERM");
198→    // Force kill after 5s if graceful shutdown fails
199→    const forceTimer = setTimeout(() => {
200→      if (backendProcess) {
201→        backendProcess.kill("SIGKILL");
202→        backendProcess = null;
203→      }
204→    }, 5_000);
205→    backendProcess.on("exit", () => {
206→      clearTimeout(forceTimer);
207→      backendProcess = null;
208→    });
209→  }
210→}
211→

 1→import Database from "better-sqlite3";
 2→import path from "path";
 3→import fs from "fs";
 4→import os from "os";
 5→import { SCHEMA_SQL, MIGRATIONS } from "@shared/schema";
 6→
 7→const DEFAULT_DB_PATH = path.join(
 8→  process.env.HOME || os.homedir(),
 9→  "Library/Application Support/com.deus.app/deus.db"
10→);
11→
12→const DB_PATH = process.env.DATABASE_PATH || DEFAULT_DB_PATH;
13→
14→let dbInstance: Database.Database | null = null;
15→
16→function initDatabase(): Database.Database {
17→  if (dbInstance) {
18→    return dbInstance;
19→  }
20→
21→  // Ensure parent directory exists (first launch)
22→  const dbDir = path.dirname(DB_PATH);
23→  if (!fs.existsSync(dbDir)) {
24→    fs.mkdirSync(dbDir, { recursive: true });
25→  }
26→
27→  console.log("Opening database:", DB_PATH);
28→
29→  try {
30→    dbInstance = new Database(DB_PATH);
31→    dbInstance.pragma("journal_mode = WAL");
32→    dbInstance.pragma("foreign_keys = ON");
33→    dbInstance.pragma("busy_timeout = 5000");
34→    dbInstance.pragma("optimize");
35→
36→    // Create all tables, indexes, and triggers (idempotent)
37→    dbInstance.exec(SCHEMA_SQL);
38→
39→    // Post-launch migrations: add new columns to existing tables.
40→    // Each ALTER TABLE may fail with "duplicate column" if already applied — skip those.
41→    for (const sql of MIGRATIONS) {
42→      try {
43→        dbInstance.exec(sql);
44→      } catch (e: unknown) {
45→        const msg = e instanceof Error ? e.message : "";
46→        if (!msg.includes("duplicate column") && !msg.includes("no such table")) throw e;
47→      }
48→    }
49→
50→    console.log("Database connected");
51→    return dbInstance;
52→  } catch (error) {
53→    console.error("Failed to open database:", error);
54→    throw error;
55→  }
56→}
57→
58→function getDatabase(): Database.Database {
59→  if (!dbInstance) {
60→    throw new Error("Database not initialized. Call initDatabase() first.");
61→  }
62→  return dbInstance;
63→}
64→
65→function closeDatabase(): void {
66→  if (dbInstance) {
67→    console.log("Closing database connection");
68→    dbInstance.pragma("optimize");
69→    dbInstance.close();
70→    dbInstance = null;
71→  }
72→}
73→
74→export { initDatabase, getDatabase, closeDatabase, DB_PATH };
75→

  1→// Browser gate page for remote device connection.
  2→// Shown when a non-localhost browser accesses Deus without a valid token.
  3→//
  4→// Three visual states:
  5→//   1. Auto-connecting — QR/link path, no form, just a clean "Connecting..." with animation
  6→//   2. Success — checkmark with spring animation, brief pause before navigating
  7→//   3. Manual entry — single code input, shown when there's no code in the URL
  8→//
  9→// In relay mode (web-production), pairing happens through a one-shot WebSocket
 10→// to the relay's /pair endpoint. In direct mode (web-dev with remote host),
 11→// pairing POSTs to the backend's /api/remote-auth/pair endpoint.
 12→
 13→import { useState, useRef, useEffect, useCallback } from "react";
 14→import { AnimatePresence, m, useReducedMotion } from "framer-motion";
 15→import { Button } from "@/components/ui/button";
 16→import { Input } from "@/components/ui/input";
 17→import { Check } from "lucide-react";
 18→import { isRelayMode, RELAY_BASE_URL } from "@/shared/config/backend.config";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Constants
 22→// ---------------------------------------------------------------------------
 23→
 24→const EASE_OUT_QUART = [0.165, 0.84, 0.44, 1] as const;
 25→const SPRING_OVERSHOOT = { type: "spring", stiffness: 300, damping: 20 } as const;
 26→const SUCCESS_HOLD_MS = 1500;
 27→
 28→// ---------------------------------------------------------------------------
 29→// Types
 30→// ---------------------------------------------------------------------------
 31→
 32→interface PairGatePageProps {
 33→  onPaired: (token: string, deviceName?: string) => void;
 34→  /** Server ID for relay mode pairing. Extracted from route params by ServerLayout. */
 35→  serverId?: string;
 36→}
 37→
 38→type PageState = "idle" | "connecting" | "success" | "error";
 39→
 40→// ---------------------------------------------------------------------------
 41→// Code normalization
 42→// ---------------------------------------------------------------------------
 43→
 44→/**
 45→ * Normalize a raw code string to canonical form: "WORD WORD".
 46→ * Treats dashes, underscores, and plus signs as word separators.
 47→ * Returns null if the result isn't a valid two-word code.
 48→ */
 49→function normalizeCode(raw: string): string | null {
 50→  const normalized = raw.replace(/[-_+]/g, " ").replace(/\s+/g, " ").trim().toUpperCase();
 51→  const parts = normalized.split(" ");
 52→  if (parts.length === 2 && parts.every((p) => /^[A-Z]{2,}$/.test(p))) {
 53→    return normalized;
 54→  }
 55→  return null;
 56→}
 57→
 58→/** Extract code from the current URL's ?pair= query parameter. */
 59→function getPairFromUrl(): string | null {
 60→  const pair = new URLSearchParams(window.location.search).get("pair");
 61→  return pair ? normalizeCode(pair) : null;
 62→}
 63→
 64→/** Extract code from a pasted URL (e.g. "https://...?pair=SOFT+TIGER"). */
 65→function extractCodeFromPastedUrl(text: string): string | null {
 66→  try {
 67→    const pair = new URL(text.trim()).searchParams.get("pair");
 68→    return pair ? normalizeCode(pair) : null;
 69→  } catch {
 70→    return null;
 71→  }
 72→}
 73→
 74→/** Extract serverId from the current URL pathname (/s/{serverId}/...). */
 75→function getServerIdFromUrl(): string | null {
 76→  const match = window.location.pathname.match(/^\/s\/([^/]+)/);
 77→  return match ? match[1] : null;
 78→}
 79→
 80→// ---------------------------------------------------------------------------
 81→// Pairing transports
 82→// ---------------------------------------------------------------------------
 83→
 84→function pairViaRelay(
 85→  serverId: string,
 86→  code: string,
 87→  deviceName: string
 88→): Promise<{ token: string }> {
 89→  return new Promise((resolve, reject) => {
 90→    const url = `${RELAY_BASE_URL}/api/servers/${encodeURIComponent(serverId)}/pair`;
 91→    const ws = new WebSocket(url);
 92→    const timeout = setTimeout(() => {
 93→      ws.close();
 94→      reject(new Error("Connection timed out. Try again."));
 95→    }, 30_000);
 96→
 97→    ws.onopen = () => {
 98→      ws.send(JSON.stringify({ type: "pair_request", code, deviceName }));
 99→    };
100→
101→    ws.onmessage = (evt) => {
102→      clearTimeout(timeout);
103→      try {
104→        const msg = JSON.parse(evt.data as string);
105→        if (msg.type === "pair_success" && msg.token) {
106→          resolve({ token: msg.token });
107→        } else if (msg.type === "pair_failed") {
108→          reject(new Error(msg.message || "Connection failed. Check your code and try again."));
109→        } else {
110→          reject(new Error("Something went wrong. Try again."));
111→        }
112→      } catch {
113→        reject(new Error("Something went wrong. Try again."));
114→      }
115→      ws.close();
116→    };
117→
118→    ws.onerror = () => {
119→      clearTimeout(timeout);
120→      reject(new Error("Unable to connect. Check your internet and try again."));
121→    };
122→
123→    ws.onclose = (evt) => {
124→      clearTimeout(timeout);
125→      if (evt.code !== 1000) {
126→        reject(new Error("Connection lost. Try again."));
127→      }
128→    };
129→  });
130→}
131→
132→async function pairViaDirect(
133→  code: string,
134→  deviceName: string
135→): Promise<{ token: string; device?: { name: string } }> {
136→  const baseUrl = `${window.location.protocol}//${window.location.host}`;
137→  const response = await fetch(`${baseUrl}/api/remote-auth/pair`, {
138→    method: "POST",
139→    headers: { "Content-Type": "application/json" },
140→    body: JSON.stringify({ code, deviceName }),
141→  });
142→
143→  if (!response.ok) {
144→    const data = await response.json().catch(() => null);
145→    throw new Error(data?.error ?? "Invalid connection code");
146→  }
147→
148→  return response.json();
149→}
150→
151→// ---------------------------------------------------------------------------
152→// Sub-components
153→// ---------------------------------------------------------------------------
154→
155→/** Pulsing dots indicator — three dots that pulse in sequence. Respects reduced motion. */
156→function PulsingDots({ reduced }: { reduced: boolean | null }) {
157→  return (
158→    <div className="flex items-center justify-center gap-1.5">
159→      {[0, 1, 2].map((i) =>
160→        reduced ? (
161→          <span
162→            key={i}
163→            className="bg-foreground/60 size-1.5 rounded-full"
164→            style={{ opacity: 0.6 }}
165→          />
166→        ) : (
167→          <m.span
168→            key={i}
169→            className="bg-foreground/60 size-1.5 rounded-full"
170→            animate={{ opacity: [0.3, 1, 0.3], scale: [0.85, 1, 0.85] }}
171→            transition={{
172→              duration: 1.2,
173→              repeat: Infinity,
174→              delay: i * 0.15,
175→              ease: "easeInOut",
176→            }}
177→          />
178→        )
179→      )}
180→    </div>
181→  );
182→}
183→
184→/** Animated checkmark — draws on with spring physics. */
185→function AnimatedCheckmark({ reduced }: { reduced: boolean | null }) {
186→  return (
187→    <m.div
188→      className="bg-success/10 flex size-20 items-center justify-center rounded-full"
189→      initial={reduced ? false : { scale: 0, opacity: 0 }}
190→      animate={{ scale: 1, opacity: 1 }}
191→      transition={reduced ? { duration: 0.1 } : SPRING_OVERSHOOT}
192→    >
193→      <m.div
194→        initial={reduced ? false : { scale: 0 }}
195→        animate={{ scale: 1 }}
196→        transition={reduced ? { duration: 0.1 } : { ...SPRING_OVERSHOOT, delay: 0.15 }}
197→      >
198→        <Check className="text-success size-10" strokeWidth={2.5} />
199→      </m.div>
200→    </m.div>
201→  );
202→}
203→
204→/** Brand mark — simple text logo for the gate page. */
205→function BrandMark() {
206→  return (
207→    <m.div
208→      className="flex items-center gap-2"
209→      initial={{ opacity: 0, y: -4 }}
210→      animate={{ opacity: 1, y: 0 }}
211→      transition={{ duration: 0.3, ease: EASE_OUT_QUART }}
212→    >
213→      <div className="bg-foreground flex size-7 items-center justify-center rounded-lg">
214→        <span className="text-background text-xs font-bold">OD</span>
215→      </div>
216→      <span className="text-muted-foreground text-sm font-medium tracking-wide">Deus</span>
217→    </m.div>
218→  );
219→}
220→
221→// ---------------------------------------------------------------------------
222→// Page states
223→// ---------------------------------------------------------------------------
224→
225→/** Auto-connecting view — shown when QR/link provides the code. */
226→function ConnectingView({ reduced }: { reduced: boolean | null }) {
227→  return (
228→    <m.div
229→      key="connecting"
230→      className="flex flex-col items-center gap-6"
231→      initial={{ opacity: 0 }}
232→      animate={{ opacity: 1 }}
233→      exit={{ opacity: 0, scale: 0.98 }}
234→      transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
235→    >
236→      <BrandMark />
237→      <div className="flex flex-col items-center gap-5">
238→        <m.h1
239→          className="text-xl font-semibold tracking-tight"
240→          initial={{ opacity: 0, y: 8 }}
241→          animate={{ opacity: 1, y: 0 }}
242→          transition={{ duration: 0.35, delay: 0.1, ease: EASE_OUT_QUART }}
243→        >
244→          Connecting...
245→        </m.h1>
246→        <PulsingDots reduced={reduced} />
247→        <m.p
248→          className="text-muted-foreground max-w-[260px] text-center text-sm"
249→          initial={{ opacity: 0 }}
250→          animate={{ opacity: 1 }}
251→          transition={{ duration: 0.3, delay: 0.3 }}
252→        >
253→          Establishing a secure connection to your computer.
254→        </m.p>
255→      </div>
256→    </m.div>
257→  );
258→}
259→
260→/** Success view — shown briefly after successful pairing. */
261→function SuccessView({ reduced }: { reduced: boolean | null }) {
262→  return (
263→    <m.div
264→      key="success"
265→      className="flex flex-col items-center gap-6"
266→      initial={{ opacity: 0 }}
267→      animate={{ opacity: 1 }}
268→      exit={{ opacity: 0 }}
269→      transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
270→    >
271→      <AnimatedCheckmark reduced={reduced} />
272→      <m.div
273→        className="flex flex-col items-center gap-2"
274→        initial={reduced ? false : { opacity: 0, y: 8 }}
275→        animate={{ opacity: 1, y: 0 }}
276→        transition={{ duration: 0.3, delay: reduced ? 0 : 0.25, ease: EASE_OUT_QUART }}
277→      >
278→        <h1 className="text-xl font-semibold tracking-tight">Connected</h1>
279→        <p className="text-muted-foreground text-sm">You're all set.</p>
280→      </m.div>
281→    </m.div>
282→  );
283→}
284→
285→/** Error view for auto-connect failure — shows error + falls back to manual input. */
286→function AutoConnectErrorView({ error, onRetry }: { error: string; onRetry: () => void }) {
287→  return (
288→    <m.div
289→      key="auto-error"
290→      className="flex flex-col items-center gap-6"
291→      initial={{ opacity: 0 }}
292→      animate={{ opacity: 1 }}
293→      transition={{ duration: 0.25, ease: EASE_OUT_QUART }}
